var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"퇴마 완료.","JPN":"退魔完了。","ENG":"Exorcism complete.","TWN":"驅魔完成。"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"덤으로 융합체들도 처리해 드렸습니다. 형제님.","JPN":"おまけで融合体も処理しましたよ、ブラザー。","ENG":"And I even took care of the hybriders for you.","TWN":"順便也幫你處理了融合體，弟兄。"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"이번엔 특별히 추가금을 받진 않을게요.","JPN":"今回は特別、追加料金はなしにしてさしあげます。","ENG":"Consider this one on the house.","TWN":"這次特別不收取額外費用。"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"굉장히 감정적이고, 무절제하군.","JPN":"非常に感情的で、節度がないな。","ENG":"How incredibly emotional. Reckless, even.","TWN":"你真是感情用事又魯莽。"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"천박하다는 말로는 부족할 정도로…… 근시안적이야.","JPN":"下品だという言葉では表しきれないほど……目の前のことしか見えていない。","ENG":"Calling you crude would be an understatement... Your perspective is so limited.","TWN":"說你膚淺都不夠……簡直是目光短淺。"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"고마워. 평소에도 그렇게 생각하거든.","JPN":"ありがとう。私もいつもそう思っているんだ。","ENG":"Thanks. That's pretty much how I see myself.","TWN":"謝謝，我平時也是這麼想的。"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"넌 좀 앞을 보면서 살았으면 하는데.","JPN":"でもあなたは、もう少し目の前を見たほうがいいと思うよ。","ENG":"But maybe you should try looking ahead for once.","TWN":"我希望你能向前看。"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"그게 무슨…….","JPN":"それはどういう……","ENG":"What are you talking about–","TWN":"那是什麼……"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"이 침식체들. 다 당신네 사람들이었다며.","JPN":"この侵食体たち、全部あなたの身内だったんでしょう。","ENG":"These C.O.s., they used to be your people, right?","TWN":"這些侵蝕體，全都是你家的人吧。"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"결국 나나 당신이나 이렇게 될 운명이라니까?","JPN":"結局あなたも私も、最後はこうなる運命なんだよ？","ENG":"In the end, you and I are heading down the same path.","TWN":"最終你或我都會變成這樣吧？"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"아니…… 아니야…….","JPN":"いや……違う……","ENG":"No... That's not…","TWN":"不…… 不會的……"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"나는…… 침식을 극복하고…… 더 나은 인류를…….","JPN":"私は……侵食を乗り越え……より進化した人類を……","ENG":"I was supposed to conquer the Corruption... to create a superior humanity...","TWN":"我……要克服侵蝕……成為更好的人……"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"너도 사실 그게 얼마나 말이 안 되는 소리인지 알고 있잖아.","JPN":"あなた自身も、それがバカげた話だってことぐらいわかっているでしょう。","ENG":"You already know how ridiculous that sounds.","TWN":"你其實也知道這有多荒謬吧。"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그 리플레이서란 놈들이 약속의 땅이니 뭐니, 헛소리한 것과 같은 이치야.","JPN":"そのリプレイサーってやつらが約束の地だのなんだの、ふざけたこと言ってたのと同じ。","ENG":"It's no different from those Replacers ranting about their \\"promised land.\\"","TWN":"那些克隆傢伙說什麼約定之地，都是胡說八道。"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"굉장히 폭력적이고, 책임감 없는 발상이지.","JPN":"すごく暴力的で、責任感のない発想だよ。","ENG":"It's an idea built on violence and complete irresponsibility.","TWN":"真是粗暴又不負責任的想法啊。"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"하, 으리으리해서 보기 좋네.","JPN":"は、豪華でいいね。","ENG":"Whoa, fancy place you've got here.","TWN":"哈，真是氣派啊。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"여길 싹 다 털면 몇 년 동안 치료에만 몰두할 수 있겠어.","JPN":"ここにあるものを全部頂戴すれば、あと数年は治療に集中できそう。","ENG":"If I clean this place out, I could afford years of treatment.","TWN":"把這裡全部搜刮一空的話，幾年內都可以專心治病了。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"후, 후후후…….","JPN":"ふ、ふふふ……","ENG":"Ha... Hahaha...","TWN":"呵，呵呵吼……"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"아까는 천박하니 뭐니 하더니 이번엔 또 웃고 있네.","JPN":"人に下品だとか言っておいて、今度は笑ってやがる。","ENG":"First, you called me crude. And now you're suddenly laughing?","TWN":"剛才還說我膚淺，現在又在笑。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"정신이 나갔나요, 형제님?","JPN":"頭大丈夫ですか、ブラザー？","ENG":"Are you losing your mind, Brother Ludwig?","TWN":"你是瘋了嗎？"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"그야, 자네 덕분에 나는 한 단계 더 나아갈 수 있게 됐으니까.","JPN":"そりゃ、君のおかげで私はさらに一歩進むことができたのだからね。","ENG":"That's because thanks to you, I can finally move forward.","TWN":"因為有你，我才能更進一步。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"여기서 긍정적인 상황 같은 건 하나도 안 보이는데.","JPN":"今ポジティブに捉えられる要素は何一つ見当たらないんだけど。","ENG":"Nothing about this situation looks positive for you.","TWN":"這裡看不到任何樂觀的情況。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_LAUGH"},"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L43_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"먼저, 가설대로 이상 침식 현상을 재현해 낼 수 있었네.","JPN":"まず、仮説通り異常侵食現象を再現できた。","ENG":"First, I confirmed my hypothesis. I successfully recreated an Aberrant Counterside Effect.","TWN":"首先，可以根據假設重現出異常侵蝕現象。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_IDLE"},"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"}}}}]`);export{e as default};